UPDATE TORDER_INFO_OR_DT SET
	cfqty = #{cfqty}
	,WKSTATUS = #{wkstatus}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{updateurkey}
WHERE ORHDKEY  = #{orhdkey}
	    AND ORDTKEY = #{ordtkey}


UPDATE TORDER_INFO_OR_HD SET
	WKSTATUS = #{wkstatus}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{updateurkey}
WHERE ORHDKEY  = #{orhdkey}

	UPDATE TORDER_INFO_OR_HD SET
		UPDATEDATE = #{sysdate}
		, UPDATEURKEY = #{surkey}

 			, WAYBILLNO = #{waybillno}


 			, ORCONFIRMDATE = #{orconfirmdate, typeHandler=GmtDateTimeFormatTypeHandler}


 			, CTKEY = #{ctkey}



			ORHDKEY = #{orhdkey}


			AND ORHDKEY IN 

				#{ORHDKEY_LIST}
